import java.util.Arrays;
import java.util.Comparator;

class Student {
    String name;
    char grade;
    Student(String name, char grade) { this.name = name; this.grade = grade; }
    public String toString() { return name + ": " + grade; }
}

class GradeComparator implements Comparator<Student> {
    @Override
    public int compare(Student a, Student b) {
        // Grade 'A' < 'B' in char comparison, so ascending char = ascending grade
        // We want A first (best grade) so ascending char order
        return Character.compare(a.grade, b.grade);
    }
}

public class App {
    public static void main(String[] args) {
        Student[] students = {
            new Student("Priya", 'C'),
            new Student("Aisha", 'A'),
            new Student("Raj", 'B')
        };
        Arrays.sort(students, new GradeComparator());
        for (Student s : students) System.out.println(s);
    }
}

