import java.util.Arrays;
import java.util.Comparator;

class Employee {
    String name, dept;
    double salary;
    Employee(String name, String dept, double salary) {
        this.name = name; this.dept = dept; this.salary = salary;
    }
    public String toString() { return name + " (" + dept + "): " + salary; }
}

public class App {
    public static void main(String[] args) {
        Employee[] staff = {
            new Employee("Raj", "Sales", 85000),
            new Employee("Aisha", "Engineering", 95000),
            new Employee("Vikram", "Sales", 68000),
            new Employee("Priya", "Engineering", 72000)
        };

        Comparator<Employee> byDeptThenSalaryDesc = new Comparator<Employee>() {
            @Override
            public int compare(Employee a, Employee b) {
                int deptCmp = a.dept.compareTo(b.dept);
                if (deptCmp != 0) return deptCmp;
                return Double.compare(b.salary, a.salary);  // salary descending
            }
        };

        Arrays.sort(staff, byDeptThenSalaryDesc);
        for (Employee e : staff) System.out.println(e);
    }
}

