exercises.expected_solution:
import java.util.Arrays;
import java.util.Comparator;

class Book {
    String title, author;
    int year;
    double rating;

    Book(String title, String author, int year, double rating) {
        this.title = title; this.author = author;
        this.year = year; this.rating = rating;
    }
}

public class App {
    static final Comparator<Book> BY_TITLE = new Comparator<Book>() {
        public int compare(Book a, Book b) { return a.title.compareTo(b.title); }
    };

    static final Comparator<Book> BY_YEAR_DESC = new Comparator<Book>() {
        public int compare(Book a, Book b) { return Integer.compare(b.year, a.year); }
    };

    static final Comparator<Book> BY_RATING_DESC = new Comparator<Book>() {
        public int compare(Book a, Book b) { return Double.compare(b.rating, a.rating); }
    };

    static void printSorted(Book[] books, Comparator<Book> cmp, String label) {
        Book[] copy = Arrays.copyOf(books, books.length);
        Arrays.sort(copy, cmp);
        System.out.println("--- " + label + " ---");
        for (Book b : copy) System.out.println(b.title);
    }

    public static void main(String[] args) {
        Book[] books = {
            new Book("Foundation", "Asimov", 1951, 8.9),
            new Book("Dune", "Herbert", 1965, 9.1),
            new Book("Clean Code", "Martin", 2008, 8.7)
        };
        printSorted(books, BY_TITLE, "By title");

        Book[] byYear = Arrays.copyOf(books, books.length);
        Arrays.sort(byYear, BY_YEAR_DESC);
        System.out.println("--- By year (newest first) ---");
        for (Book b : byYear) System.out.println(b.title + " (" + b.year + ")");

        Book[] byRating = Arrays.copyOf(books, books.length);
        Arrays.sort(byRating, BY_RATING_DESC);
        System.out.println("--- By rating (highest first) ---");
        for (Book b : byRating) System.out.println(b.title + ": " + b.rating);
    }
}

