exercises.expected_solution:
import java.util.Arrays;
import java.util.Comparator;

class Product {
    String name;
    double price;
    Product(String name, double price) { this.name = name; this.price = price; }
    public String toString() { return name; }
}

public class App {
    static Comparator<Product> getComparator(String key) {
        switch (key) {
            case "name":
                return new Comparator<Product>() {
                    public int compare(Product a, Product b) { return a.name.compareTo(b.name); }
                };
            case "price_asc":
                return new Comparator<Product>() {
                    public int compare(Product a, Product b) { return Double.compare(a.price, b.price); }
                };
            case "price_desc":
                return new Comparator<Product>() {
                    public int compare(Product a, Product b) { return Double.compare(b.price, a.price); }
                };
            default:
                return new Comparator<Product>() {
                    public int compare(Product a, Product b) { return 0; }
                };
        }
    }

    static void sortAndPrint(Product[] products, String key) {
        Product[] copy = Arrays.copyOf(products, products.length);
        Arrays.sort(copy, getComparator(key));
        System.out.print("Sorted by " + key + ":\n");
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < copy.length; i++) {
            if (i > 0) sb.append(",");
            sb.append(copy[i].name);
        }
        System.out.println(sb);
    }

    public static void main(String[] args) {
        Product[] catalog = {
            new Product("Monitor", 18999),
            new Product("Mouse", 599),
            new Product("Keyboard", 1999)
        };
        sortAndPrint(catalog, "name");
        sortAndPrint(catalog, "price_asc");
        sortAndPrint(catalog, "price_desc");
    }
}

