import java.util.Arrays;
import java.util.Comparator;

class Movie implements Comparable<Movie> {
    String title;
    int year;
    double rating;

    Movie(String title, int year, double rating) {
        this.title = title; this.year = year; this.rating = rating;
    }

    @Override
    public int compareTo(Movie other) {
        return Integer.compare(this.year, other.year);  // natural: by year
    }

    static final Comparator<Movie> BY_TITLE =
        new Comparator<Movie>() {
            public int compare(Movie a, Movie b) { return a.title.compareTo(b.title); }
        };

    static final Comparator<Movie> BY_RATING_DESC =
        new Comparator<Movie>() {
            public int compare(Movie a, Movie b) { return Double.compare(b.rating, a.rating); }
        };
}

public class App {
    public static void main(String[] args) {
        Movie[] movies = {
            new Movie("Pulp Fiction", 1994, 8.9),
            new Movie("Interstellar", 2014, 8.6),
            new Movie("Godfather", 1972, 9.2)
        };

        Movie[] nat = Arrays.copyOf(movies, movies.length);
        Arrays.sort(nat);
        System.out.println("--- Natural (year) ---");
        for (Movie m : nat) System.out.println(m.title + " (" + m.year + "): " + m.rating);

        Movie[] byTitle = Arrays.copyOf(movies, movies.length);
        Arrays.sort(byTitle, Movie.BY_TITLE);
        System.out.println("--- By title ---");
        for (Movie m : byTitle) System.out.println(m.title);

        Movie[] byRating = Arrays.copyOf(movies, movies.length);
        Arrays.sort(byRating, Movie.BY_RATING_DESC);
        System.out.println("--- By rating (highest) ---");
        for (Movie m : byRating) System.out.println(m.title + ": " + m.rating);
    }
}

abstract class Vehicle {
    protected String color;
    Vehicle(String color) { this.color = color; }
    public abstract String describe();
}

class Car extends Vehicle {
    private int numDoors;
    Car(String color, int numDoors) { super(color); this.numDoors = numDoors; }
    @Override public String describe() { return color + " Car"; }
    public int getNumDoors() { return numDoors; }
}

class Motorcycle extends Vehicle {
    private boolean hasSidecar;
    Motorcycle(String color, boolean hasSidecar) { super(color); this.hasSidecar = hasSidecar; }
    @Override public String describe() { return color + " Motorcycle"; }
    public boolean hasSidecar() { return hasSidecar; }
}

public class App {
    static void printDetails(Vehicle v) {
        System.out.print(v.describe());  // polymorphic
        if (v instanceof Car c) {
            System.out.println(" — " + c.getNumDoors() + " doors");
        } else if (v instanceof Motorcycle m) {
            System.out.println(" — " + (m.hasSidecar() ? "with sidecar" : "no sidecar"));
        } else {
            System.out.println();
        }
    }

    public static void main(String[] args) {
        printDetails(new Car("Red", 4));
        printDetails(new Motorcycle("Blue", false));
    }
}

