import java.util.Arrays;
import java.util.Comparator;

class Player {
    String name, country;
    int score, level;

    Player(String name, int score, int level, String country) {
        this.name = name; this.score = score;
        this.level = level; this.country = country;
    }
}

class Leaderboard {
    private Player[] players;
    private int count;

    Leaderboard(int capacity) {
        players = new Player[capacity];
        count = 0;
    }

    void addPlayer(Player p) {
        if (count < players.length) players[count++] = p;
    }

    Player[] rank(Comparator<Player> cmp) {
        Player[] copy = Arrays.copyOf(players, count);
        Arrays.sort(copy, cmp);
        return copy;
    }

    static final Comparator<Player> BY_SCORE_DESC =
        new Comparator<Player>() {
            public int compare(Player a, Player b) { return Integer.compare(b.score, a.score); }
        };

    static final Comparator<Player> BY_LEVEL_DESC =
        new Comparator<Player>() {
            public int compare(Player a, Player b) { return Integer.compare(b.level, a.level); }
        };

    static final Comparator<Player> BY_NAME =
        new Comparator<Player>() {
            public int compare(Player a, Player b) { return a.name.compareTo(b.name); }
        };
}

public class App {
    static void printTop3(Player[] ranked, String label, java.util.function.Function<Player, String> fmt) {
        System.out.println("=== " + label + " ===");
        int n = Math.min(3, ranked.length);
        for (int i = 0; i < n; i++) {
            System.out.println((i + 1) + ". " + fmt.apply(ranked[i]));
        }
    }

    public static void main(String[] args) {
        Leaderboard lb = new Leaderboard(10);
        lb.addPlayer(new Player("Aisha", 9500, 12, "India"));
        lb.addPlayer(new Player("Raj", 8200, 9, "India"));
        lb.addPlayer(new Player("Priya", 7800, 8, "India"));
        lb.addPlayer(new Player("Vikram", 7200, 10, "India"));
        lb.addPlayer(new Player("Anita", 6500, 7, "India"));

        Player[] byScore = lb.rank(Leaderboard.BY_SCORE_DESC);
        System.out.println("=== By Score ===");
        for (int i = 0; i < 3; i++) System.out.println((i+1) + ". " + byScore[i].name + ": " + byScore[i].score + " pts");

        Player[] byLevel = lb.rank(Leaderboard.BY_LEVEL_DESC);
        System.out.println("=== By Level ===");
        for (int i = 0; i < 3; i++) System.out.println((i+1) + ". " + byLevel[i].name + ": lvl " + byLevel[i].level);

        Player[] byName = lb.rank(Leaderboard.BY_NAME);
        System.out.println("=== By Name ===");
        for (int i = 0; i < 3; i++) System.out.println((i+1) + ". " + byName[i].name);
    }
}

