abstract class Taxable {
    public abstract double computeTax();
}

class IncomeSource extends Taxable {
    private double amount;
    IncomeSource(double amount) { this.amount = amount; }
    @Override public double computeTax() { return amount * 0.30; }
}

class Investment extends Taxable {
    private double value;
    Investment(double value) { this.value = value; }
    @Override public double computeTax() { return value * 0.10; }
}

class FreelanceWork extends Taxable {
    private double earnings;
    FreelanceWork(double earnings) { this.earnings = earnings; }
    @Override public double computeTax() { return earnings * 0.18 + 500; }
}

public class App {
    public static void main(String[] args) {
        Taxable[] taxables = {
            new IncomeSource(100000),
            new Investment(50000),
            new FreelanceWork(15666.67)
        };

        String[] labels = {"Income tax", "Capital gains", "Freelance tax"};
        for (int i = 0; i < taxables.length; i++) {
            System.out.printf("%s: %.1f%n", labels[i], taxables[i].computeTax());
        }
    }
}

