import java.util.Arrays;
import java.util.Comparator;

interface Recommendable {
    double relevanceScore();
    default boolean isHighRelevance() { return relevanceScore() >= 8.0; }
}

class Product implements Comparable<Product>, Recommendable {
    private String name, category;
    private double price, relevance;

    Product(String name, String category, double price, double relevance) {
        this.name = name; this.category = category;
        this.price = price; this.relevance = relevance;
    }

    public String getName() { return name; }
    public String getCategory() { return category; }
    public double getPrice() { return price; }
    @Override public double relevanceScore() { return relevance; }

    @Override
    public int compareTo(Product other) {
        return Double.compare(other.relevance, this.relevance); // desc
    }

    @Override
    public String toString() { return name + ": ₹" + (int)price; }
}

class Feed {
    private Product[] products;
    private int count;

    Feed(int capacity) { products = new Product[capacity]; count = 0; }

    void add(Product p) { if (count < products.length) products[count++] = p; }

    static final Comparator<Product> BY_PRICE_ASC =
        new Comparator<Product>() {
            public int compare(Product a, Product b) { return Double.compare(a.getPrice(), b.getPrice()); }
        };

    static final Comparator<Product> BY_CATEGORY =
        new Comparator<Product>() {
            public int compare(Product a, Product b) { return a.getCategory().compareTo(b.getCategory()); }
        };

    static final Comparator<Product> BY_RELEVANCE_DESC =
        new Comparator<Product>() {
            public int compare(Product a, Product b) { return Double.compare(b.relevanceScore(), a.relevanceScore()); }
        };

    Product[] getHighRelevance() {
        int cnt = 0;
        for (int i = 0; i < count; i++) if (products[i].isHighRelevance()) cnt++;
        Product[] result = new Product[cnt];
        int j = 0;
        for (int i = 0; i < count; i++) {
            if (products[i].isHighRelevance()) result[j++] = products[i];
        }
        Arrays.sort(result, BY_RELEVANCE_DESC);
        return result;
    }

    Product[] sortedBy(Comparator<Product> cmp) {
        Product[] copy = Arrays.copyOf(products, count);
        Arrays.sort(copy, cmp);
        return copy;
    }
}

public class App {
    public static void main(String[] args) {
        Feed feed = new Feed(20);
        feed.add(new Product("Monitor", "Electronics", 18999, 7.5));
        feed.add(new Product("Mouse", "Electronics", 799, 9.2));
        feed.add(new Product("Keyboard", "Electronics", 1999, 8.5));
        feed.add(new Product("Python Book", "Books", 849, 7.8));
        feed.add(new Product("USB Hub", "Electronics", 499, 6.9));

        System.out.println("High relevance (>=8.0):");
        for (Product p : feed.getHighRelevance()) {
            System.out.println(p.getName() + " (" + p.relevanceScore() + ")");
        }

        System.out.println("\nSorted by price:");
        for (Product p : feed.sortedBy(Feed.BY_PRICE_ASC)) {
            System.out.println(p);
        }
    }
}
